const express = require('express');
const router = express.Router();
const bodyParser = require('body-parser');

// Assuming User is an existing Model in your application
// The structure of user object might vary based on your data model and database schema.
let User = {}; // Replace this with the actual user model instance

router.get('/profile', bodyParser.json(), async (req, res) => {
  try {
    const user = await User.findById(req.user._id);
    if (!user) return res.status(404).send('User not found');

    res.send(user);
  } catch (err) {
    console.error(err);
    res.status(500).send('Error retrieving user profile');
  }
});

module.exports = router;